+	if IsSharedServerMode() {
+		dir, err := SharedServerDir()
+		if err != nil {
+			fmt.Fprintf(os.Stderr, "Warning: shared server directory unavailable, using per-project mode: %v\n", err)
+			return beadsDir
+		}
+		return dir
+	}
 	return beadsDir
 }

